const observerOptions={threshold:.12,rootMargin:"0px 0px -80px 0px"},scrollObserver=new IntersectionObserver((e,t)=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("reveal"),t.unobserve(e.target))})},observerOptions);function initializeScrollAnimations(){$$(".animate-on-scroll").forEach(e=>scrollObserver.observe(e))}function setupNavbarScrollEffect(){const e=$("#navbar");if(!e)return;const t=throttle(()=>{getScrollPos()>50?e.classList.add("scrolled"):e.classList.remove("scrolled")},100);window.addEventListener("scroll",t,{passive:!0}),t()}function handleParallax(){const e=throttle(()=>{const e=getScrollPos();$$(".parallax").forEach(t=>{const o=Number(t.dataset.speed||.08);t.style.transform=`translateY(${e*o}px)`})},16);window.addEventListener("scroll",e,{passive:!0})}function smoothScroll(e){const t=document.getElementById(e);if(!t)return;const o=t.getBoundingClientRect().top+window.pageYOffset-70;window.scrollTo({top:o,behavior:"smooth"})}